import json, re

# Extract the JSON part from scout_result (remove markdown fences and extra text)
json_match = re.search(r'\{.*\}', scout_result, re.DOTALL)
if json_match:
    json_str = json_match.group(0)
else:
    json_str = "{}"

try:
    data = json.loads(json_str)
    candidates = data.get("candidates", []) or []
except (json.JSONDecodeError, ValueError, AttributeError):
    data, candidates = {}, []

top = candidates[:3]

enrichments = {}
for i in range(len(top)):
    enrichments[i] = {"candidate": top[i]}

print(f"Got {len(candidates)} candidates; deep-diving top {len(top)}")
```

